#nullable enable // autogenerated

using System.Collections.Generic;
using MukioI18n;
using MVZ2Logic;
using MVZ2Logic.Definitions;
using MVZ2Logic.Localization;
using MVZ2Logic.Options;
using MVZ2Logic.Saves;

namespace MVZ2.GameContent.Options
{
    [AutoOptionWidgetDefinition(LogicOptionWidgetNames.hpBarsAmountMode)]
    public class HPBarsAmountModeOptionDropdown : OptionDropdownDefinition
    {
        public HPBarsAmountModeOptionDropdown(string nsp, string name) : base(nsp, name)
        {
        }
        public override bool ShouldEnable(IOptionContext context)
        {
            return Global.Saves.IsHPBarUnlocked() || Global.Debugs.CanUseDebugFeatures();
        }
        public override int GetValue(IOptionContext context)
        {
            return Global.Options.GetHPBarAmountMode();
        }
        public override void FillItems(IOptionContext context, List<string> items)
        {
            var localization = Global.Localization;
            items.Add(localization.GetTextParticular(HP_BARS_AMOUNT_MODE_HIDDEN, LogicStrings.CONTEXT_HP_BARS_AMOUNT_MODE));
            items.Add(localization.GetTextParticular(HP_BARS_AMOUNT_MODE_CURRENT_ONLY, LogicStrings.CONTEXT_HP_BARS_AMOUNT_MODE));
            items.Add(localization.GetTextParticular(HP_BARS_AMOUNT_MODE_CURRENT_AND_MAX, LogicStrings.CONTEXT_HP_BARS_AMOUNT_MODE));
        }
        public override void OnValueChanged(IOptionContext context, int index)
        {
            Global.Options.SetOptionInt(LogicOptionItemID.hpBarAmountMode, index);
            Global.Options.SaveOptions();
        }
        [TranslateMsg("血条数值模式", LogicStrings.CONTEXT_HP_BARS_AMOUNT_MODE)]
        public const string HP_BARS_AMOUNT_MODE_HIDDEN = "隐藏";
        [TranslateMsg("血条数值模式", LogicStrings.CONTEXT_HP_BARS_AMOUNT_MODE)]
        public const string HP_BARS_AMOUNT_MODE_CURRENT_ONLY = "当前血量";
        [TranslateMsg("血条数值模式", LogicStrings.CONTEXT_HP_BARS_AMOUNT_MODE)]
        public const string HP_BARS_AMOUNT_MODE_CURRENT_AND_MAX = "全部";
    }
}
